Refactor `apps/server/src/lib/version.ts` to support dev build detection and a version override env var.

## Current State

The file currently has a single exported constant:
```typescript
import { createRequire } from 'module';
declare const __CLI_VERSION__: string | undefined;
export const SERVER_VERSION: string =
  typeof __CLI_VERSION__ !== 'undefined'
    ? __CLI_VERSION__
    : (createRequire(import.meta.url)('../../package.json') as { version: string }).version;
```

## Implementation

Replace the entire file with:

```typescript
import { createRequire } from 'module';
import { env } from '../env.js';

declare const __CLI_VERSION__: string | undefined;

const DEV_VERSION_PATTERN = /^0\.0\.0/;

/**
 * Resolved server version string.
 *
 * Priority: DORKOS_VERSION_OVERRIDE > __CLI_VERSION__ (esbuild) > package.json fallback.
 */
export const SERVER_VERSION: string = resolveVersion();

/** Whether the server is running a development build (not from CLI bundle). */
export const IS_DEV_BUILD: boolean = checkDevBuild(SERVER_VERSION);

function resolveVersion(): string {
  if (env.DORKOS_VERSION_OVERRIDE) return env.DORKOS_VERSION_OVERRIDE;
  if (typeof __CLI_VERSION__ !== 'undefined') return __CLI_VERSION__;
  return (createRequire(import.meta.url)('../../package.json') as { version: string }).version;
}

function checkDevBuild(version: string): boolean {
  // Override explicitly opts out of dev mode
  if (env.DORKOS_VERSION_OVERRIDE) return false;
  // CLI bundle injects __CLI_VERSION__ — not a dev build
  if (typeof __CLI_VERSION__ !== 'undefined') return false;
  // Sentinel version from package.json
  return DEV_VERSION_PATTERN.test(version);
}
```

## Rename env var in `apps/server/src/env.ts`

In the `serverEnvSchema` object, rename:
```typescript
// Before:
DORKOS_VERSION: z.string().optional(),
// After:
DORKOS_VERSION_OVERRIDE: z.string().optional(),
```

## Rename env var in `turbo.json`

In `globalPassThroughEnv` array, change `"DORKOS_VERSION"` to `"DORKOS_VERSION_OVERRIDE"`.

## Server Tests

Create `apps/server/src/lib/__tests__/version.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Because version.ts uses top-level module constants, we need to re-import
// after mocking env. Use vi.resetModules() between tests.

describe('version resolution', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    vi.resetModules();
    process.env = { ...originalEnv };
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  it('uses DORKOS_VERSION_OVERRIDE when set', async () => {
    process.env.DORKOS_VERSION_OVERRIDE = '1.5.0';
    const { SERVER_VERSION } = await import('../version.js');
    expect(SERVER_VERSION).toBe('1.5.0');
  });

  it('is not dev build when DORKOS_VERSION_OVERRIDE is set', async () => {
    process.env.DORKOS_VERSION_OVERRIDE = '0.0.0';
    const { IS_DEV_BUILD } = await import('../version.js');
    expect(IS_DEV_BUILD).toBe(false);
  });

  it('falls back to package.json version when no override or CLI version', async () => {
    const { SERVER_VERSION } = await import('../version.js');
    // package.json has 0.0.0
    expect(SERVER_VERSION).toBe('0.0.0');
  });

  it('detects dev build when version is 0.0.0', async () => {
    const { IS_DEV_BUILD } = await import('../version.js');
    expect(IS_DEV_BUILD).toBe(true);
  });
