## Create New File

Create `apps/client/src/layers/features/status/lib/version-compare.ts`:

```typescript
/**
 * Simple semver comparison utilities for version display.
 *
 * @module features/status/lib/version-compare
 */

/** Returns true if version `a` is newer than version `b` (simple semver comparison). */
export function isNewer(a: string, b: string): boolean {
  const [aMaj, aMin, aPat] = a.split('.').map(Number);
  const [bMaj, bMin, bPat] = b.split('.').map(Number);
  if (aMaj !== bMaj) return aMaj > bMaj;
  if (aMin !== bMin) return aMin > bMin;
  return aPat > bPat;
}

/** Returns true if major or minor version changed (not just patch). */
export function isFeatureUpdate(latest: string, current: string): boolean {
  const [latMaj, latMin] = latest.split('.').map(Number);
  const [curMaj, curMin] = current.split('.').map(Number);
  return latMaj !== curMaj || latMin !== curMin;
}
```

