## Component Logic

Add the dev mode early return at the start of the component body, before the existing `hasUpdate` logic:

```typescript
export function VersionItem({ version, latestVersion, isDevMode }: VersionItemProps) {
  const [copied, setCopied] = useState(false);

  // Dev mode: render DEV badge — no update checks
  if (isDevMode) {
    return (
      <span
        className="rounded bg-amber-500/15 px-1.5 py-0.5 text-[10px] font-semibold tracking-wider text-amber-600 dark:text-amber-400"
        aria-label="Development build"
      >
        DEV
      </span>
    );
  }

  const hasUpdate = latestVersion !== null && isNewer(latestVersion, version);
  // ... rest unchanged
}
```

The DEV badge styling:
- `rounded` — subtle rounded corners
- `bg-amber-500/15` — very light amber background (15% opacity)
- `px-1.5 py-0.5` — compact padding
- `text-[10px]` — very small text matching status bar scale
- `font-semibold tracking-wider` — bold with letter-spacing for badge feel
- `text-amber-600 dark:text-amber-400` — amber text, lighter in dark mode

