## StatusLine Wiring

In `apps/client/src/layers/features/status/ui/StatusLine.tsx`, add dismiss state reading and handler.

Add imports at top:
```typescript
import { useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
```

Note: `useQueryClient` may already be available if TanStack Query is used elsewhere. Check existing imports.

Inside the `StatusLine` component body, after the existing `const { data: serverConfig }` query:

```typescript
const queryClient = useQueryClient();

const dismissedVersions: string[] = serverConfig?.dismissedUpgradeVersions ?? [];

const handleDismissVersion = useCallback(
  async (version: string) => {
    const updated = [...dismissedVersions, version];
    await transport.updateConfig({
      ui: { dismissedUpgradeVersions: updated },
    });
    queryClient.invalidateQueries({ queryKey: ['config'] });
  },
  [dismissedVersions, transport, queryClient]
);
```

Update the version entry in the entries builder:

```typescript
if (showStatusBarVersion && serverConfig) {
  const isDismissed = serverConfig.latestVersion
    ? dismissedVersions.includes(serverConfig.latestVersion)
    : false;

  entries.push({
    key: 'version',
    node: (
      <VersionItem
        version={serverConfig.version}
        latestVersion={serverConfig.latestVersion}
        isDevMode={serverConfig.isDevMode}
        isDismissed={isDismissed}
        onDismiss={handleDismissVersion}
      />
    ),
  });
}
```

Note: Check that `transport.updateConfig()` exists on the Transport interface. It should correspond to `PATCH /api/config`. If the method name differs, match whatever the transport interface provides.

